#include<bits/stdc++.h>
using namespace std;
int main(){
    int dp[1000001][2]={0},n,h[1000010];
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>h[i];
    }
    dp[1][0]=h[1];
    for(int i=2;i<=n;i++){
        dp[i][1]=min(dp[i-2][0],dp[i-1][0]);
        dp[i][0]=min(dp[i-1][0]+h[i],dp[i-1][1]+h[i]);
    }
    cout<<min(dp[n][0],dp[n][1]);
    return 0;
}
